#!/usr/bin/env dotnet
#:include *.cs
#:include Models/*.cs
#:exclude Scratch.cs

var person = new Person("Ada", "Lovelace");
Console.WriteLine(NameHelper.ToUpper(person.FullName));

static class NameHelper
{
    public static string ToUpper(string name) => name.ToUpperInvariant();
}

record Person(string FirstName, string LastName)
{
    public string FullName => $"{FirstName} {LastName}";
}

